SELECT COUNT(*) AS "totalCount", SUM(CASE WHEN t.status_code = 'a001' THEN 1 ELSE 0 END) AS "expectedCount", SUM(CASE WHEN t.status_code = 'a002' THEN 1 ELSE 0 END) AS "progressCount", SUM(CASE WHEN t.status_code = 'a003' THEN 1 ELSE 0 END) AS "endCount" FROM test t JOIN project_version pv ON t.version_id = pv.version_id JOIN project p ON pv.project_id = p.project_id LEFT JOIN users assignee ON t.assignee_id = assignee.user_id WHERE p.project_id = #{projectId} AND p.owner_id = #{loginUserId}
AND p.project_name LIKE '%' || #{projectName} || '%'
AND pv.version_name LIKE '%' || #{versionName} || '%'
AND t.team_name LIKE '%' || #{teamName} || '%'
AND t.title LIKE '%' || #{title} || '%'
AND t.status_code = #{statusCode}
AND t.test_type_code = #{testTypeCode}
AND t.priority_code = #{priorityCode}
AND assignee.user_name LIKE '%' || #{assigneeName} || '%'

SELECT COUNT(*) AS "totalCount", SUM(CASE WHEN t.status_code = 'a001' THEN 1 ELSE 0 END) AS "expectedCount", SUM(CASE WHEN t.status_code = 'a002' THEN 1 ELSE 0 END) AS "progressCount", SUM(CASE WHEN t.status_code = 'a003' THEN 1 ELSE 0 END) AS "endCount" FROM test t JOIN project_version pv ON t.version_id = pv.version_id JOIN project p ON pv.project_id = p.project_id LEFT JOIN users assignee ON t.assignee_id = assignee.user_id WHERE p.project_id = #{projectId}
AND p.project_name LIKE '%' || #{projectName} || '%'
AND pv.version_name LIKE '%' || #{versionName} || '%'
AND t.team_name LIKE '%' || #{teamName} || '%'
AND t.title LIKE '%' || #{title} || '%'
AND t.status_code = #{statusCode}
AND t.test_type_code = #{testTypeCode}
AND t.priority_code = #{priorityCode}
AND assignee.user_name LIKE '%' || #{assigneeName} || '%'

SELECT t.test_id AS "testId", t.version_id AS "versionId", t.title AS "title", t.priority_code AS "priorityCode", t.test_type_code AS "testTypeCode", t.status_code AS "statusCode", t.assignee_id AS "assigneeId", t.description AS "description", TO_CHAR(t.start_date, 'YYYY-MM-DD') AS "startDate", TO_CHAR(t.end_date, 'YYYY-MM-DD') AS "endDate", t.created_by AS "createdBy", TO_CHAR(t.created_at, 'YYYY-MM-DD') AS "createdAt", TO_CHAR(t.updated_at, 'YYYY-MM-DD') AS "updatedAt", t.team_name AS "teamName"
FROM test t JOIN project_version pv ON t.version_id = pv.version_id
WHERE t.test_id = #{testId} AND pv.project_id = #{projectId}

